30	    inline fn shouldSkipLine(line: []const u8) bool {
31	        if (line.len == 0 or
32	            // comments
33	            line[0] == ';' or
34	            line[0] == '#') return true;
35	
36	        // check the rest is whitespace
37	        for (line) |c| {
38	            switch (c) {
39	                ' ', '\t', '\n', '\r' => {},
40	                '#', ';' => return true,
41	                else => return false,
42	            }
43	        }
44	        return true;
45	    }
