525	    fn commitRopePart(this: *Parser, arena_allocator: Allocator, ropealloc: Allocator, unesc: *std.array_list.Managed(u8), existing_rope: *?*Rope) OOM!void {
526	        _ = this; // autofix
527	        const slice = try arena_allocator.dupe(u8, unesc.items[0..]);
528	        const expr = Expr.init(E.String, E.String{ .data = slice }, Loc.Empty);
529	        if (existing_rope.*) |_r| {
530	            const r: *Rope = _r;
531	            _ = try r.append(expr, ropealloc);
532	        } else {
533	            existing_rope.* = try ropealloc.create(Rope);
