541	    fn strToRope(ropealloc: Allocator, key: []const u8) OOM!*Rope {
542	        var dot_idx = nextDot(key) orelse {
543	            const rope = try ropealloc.create(Rope);
544	            rope.* = .{
545	                .head = Expr.init(E.String, E.String.init(key), Loc.Empty),
546	            };
547	            return rope;
548	        };
549	        var rope = try ropealloc.create(Rope);
550	        const head = rope;
551	        rope.* = .{
552	            .head = Expr.init(E.String, E.String.init(key[0..dot_idx]), Loc.Empty),
553	            .next = null,
554	        };
555	
556	        while (dot_idx + 1 < key.len) {
557	            const next_dot_idx = dot_idx + 1 + (nextDot(key[dot_idx + 1 ..]) orelse {
558	                const rest = key[dot_idx + 1 ..];
559	                rope = try rope.append(Expr.init(E.String, E.String.init(rest), Loc.Empty), ropealloc);
560	                break;
561	            });
562	            const part = key[dot_idx + 1 .. next_dot_idx];
563	            rope = try rope.append(Expr.init(E.String, E.String.init(part), Loc.Empty), ropealloc);
564	            dot_idx = next_dot_idx;
565	        }
566	
567	        return head;
568	    }
