602	    fn stringNeedsQuotes(str: String) bool {
603	        if (str.isEmpty()) {
604	            return true;
605	        }
606	
607	        switch (str.charAt(str.length() - 1)) {
608	            // whitespace characters
609	            ' ',
610	            '\t',
611	            '\n',
612	            '\r',
613	            // trailing colon can be misinterpreted as a mapping indicator
614	            // https://github.com/oven-sh/bun/issues/25439
615	            ':',
616	            => return true,
617	            else => {},
618	        }
619	
620	        switch (str.charAt(0)) {
621	            // starting with an indicator character requires quotes
622	            '&',
623	            '*',
624	            '?',
625	            '|',
626	            '-',
627	            '<',
628	            '>',
629	            '!',
630	            '%',
631	            '@',
632	            ':',
633	            ',',
634	            '[',
635	            ']',
636	            '{',
637	            '}',
638	            '#',
639	            '\'',
640	            '"',
641	            '`',
642	            // starting with whitespace requires quotes
643	            ' ',
644	            '\t',
645	            '\n',
646	            '\r',
647	            => return true,
648	
649	            else => {},
650	        }
651	
652	        const keywords = &.{
653	            "true",
654	            "True",
655	            "TRUE",
656	            "false",
657	            "False",
658	            "FALSE",
659	            "yes",
660	            "Yes",
661	            "YES",
662	            "no",
663	            "No",
664	            "NO",
665	            "on",
666	            "On",
667	            "ON",
668	            "off",
669	            "Off",
670	            "OFF",
671	            "n",
672	            "N",
673	            "y",
674	            "Y",
675	            "null",
676	            "Null",
677	            "NULL",
678	            "~",
679	            ".inf",
680	            ".Inf",
681	            ".INF",
682	            ".nan",
683	            ".NaN",
684	            ".NAN",
685	        };
686	
687	        inline for (keywords) |keyword| {
688	            if (str.eqlComptime(keyword)) {
689	                return true;
690	            }
691	        }
