693	        var i: usize = 0;
694	        while (i < str.length()) {
695	            switch (str.charAt(i)) {
696	                // flow indicators need to be quoted always
697	                '{',
698	                '}',
699	                '[',
700	                ']',
701	                ',',
702	                => return true,
703	
704	                ':',
705	                => {
706	                    if (i + 1 < str.length()) {
707	                        switch (str.charAt(i + 1)) {
708	                            ' ',
709	                            '\t',
710	                            '\n',
711	                            '\r',
712	                            => return true,
713	                            else => {},
714	                        }
715	                    }
716	                    i += 1;
717	                },
718	
719	                '#',
720	                '`',
721	                '\'',
722	                => return true,
723	
724	                '-' => {
