729	                        switch (str.charAt(i + 3)) {
730	                            ' ',
731	                            '\t',
732	                            '\r',
733	                            '\n',
734	                            '[',
735	                            ']',
736	                            '{',
737	                            '}',
738	                            ',',
739	                            => return true,
