929	pub fn parse(
930	    global: *jsc.JSGlobalObject,
931	    callFrame: *jsc.CallFrame,
932	) bun.JSError!jsc.JSValue {
933	    var arena: bun.ArenaAllocator = .init(bun.default_allocator);
934	    defer arena.deinit();
935	    const allocator = arena.allocator();
936	
937	    var ast_memory_allocator = bun.handleOom(allocator.create(ast.ASTMemoryAllocator));
938	    var ast_scope = ast_memory_allocator.enter(allocator);
939	    defer ast_scope.exit();
940	
941	    const input_value = callFrame.argumentsAsArray(1)[0];
942	
943	    const input: jsc.Node.BlobOrStringOrBuffer = try jsc.Node.BlobOrStringOrBuffer.fromJS(global, arena.allocator(), input_value) orelse input: {
944	        var str = try input_value.toBunString(global);
945	        defer str.deref();
946	        break :input .{ .string_or_buffer = .{ .string = str.toSlice(arena.allocator()) } };
947	    };
948	    defer input.deinit();
949	
950	    var log = logger.Log.init(bun.default_allocator);
951	    defer log.deinit();
952	
953	    const source = &logger.Source.initPathString("input.yaml", input.slice());
954	
955	    const root = bun.interchange.yaml.YAML.parse(source, &log, arena.allocator()) catch |err| return switch (err) {
956	        error.OutOfMemory => |oom| oom,
957	        error.StackOverflow => global.throwStackOverflow(),
958	        else => {
959	            if (log.msgs.items.len > 0) {
960	                const first_msg = log.msgs.items[0];
961	                const error_text = first_msg.data.text;
962	                return global.throwValue(global.createSyntaxErrorInstance("YAML Parse error: {s}", .{error_text}));
963	            }
964	            return global.throwValue(global.createSyntaxErrorInstance("YAML Parse error: Unable to parse YAML string", .{}));
965	        },
966	    };
967	
968	    var ctx: ParserCtx = .{
969	        .seen_objects = .init(arena.allocator()),
970	        .stack_check = .init(),
971	        .global = global,
972	        .root = root,
973	        .result = .zero,
974	    };
975	    defer ctx.deinit();
976	
977	    MarkedArgumentBuffer.run(ParserCtx, &ctx, &ParserCtx.run);
978	
979	    return ctx.result;
980	}
981	
982	const ParserCtx = struct {
983	    seen_objects: std.AutoHashMap(*const anyopaque, JSValue),
984	    stack_check: bun.StackCheck,
985	
986	    global: *JSGlobalObject,
987	    root: Expr,
988	
989	    result: JSValue,
990	
991	    pub fn deinit(ctx: *ParserCtx) void {
992	        ctx.seen_objects.deinit();
993	    }
994	
995	    pub fn run(ctx: *ParserCtx, args: *MarkedArgumentBuffer) callconv(.c) void {
996	        ctx.result = ctx.toJS(args, ctx.root) catch |err| switch (err) {
997	            error.OutOfMemory => {
998	                ctx.result = ctx.global.throwOutOfMemoryValue();
999	                return;
1000	            },
1001	            error.JSError, error.JSTerminated => {
1002	                ctx.result = .zero;
1003	                return;
1004	            },
1005	            error.StackOverflow => {
1006	                ctx.result = ctx.global.throwStackOverflow() catch .zero;
1007	                return;
1008	            },
1009	        };
1010	    }
1011	
1012	    const ToJSError = JSError || bun.StackOverflow;
1013	
1014	    pub fn toJS(ctx: *ParserCtx, args: *MarkedArgumentBuffer, expr: Expr) ToJSError!JSValue {
1015	        if (!ctx.stack_check.isSafeToRecurse()) {
1016	            return error.StackOverflow;
1017	        }
1018	        switch (expr.data) {
1019	            .e_null => return .null,
1020	            .e_boolean => |boolean| return .jsBoolean(boolean.value),
1021	            .e_number => |number| return .jsNumber(number.value),
1022	            .e_string => |str| {
1023	                return str.toJS(bun.default_allocator, ctx.global);
1024	            },
1025	            .e_array => {
1026	                if (ctx.seen_objects.get(expr.data.e_array)) |arr| {
1027	                    return arr;
1028	                }
1029	
1030	                var arr = try JSValue.createEmptyArray(ctx.global, expr.data.e_array.items.len);
1031	
1032	                args.append(arr);
1033	                try ctx.seen_objects.put(expr.data.e_array, arr);
1034	
1035	                for (expr.data.e_array.slice(), 0..) |item, _i| {
1036	                    const i: u32 = @intCast(_i);
1037	                    const value = try ctx.toJS(args, item);
1038	                    try arr.putIndex(ctx.global, i, value);
1039	                }
1040	
1041	                return arr;
1042	            },
1043	            .e_object => {
1044	                if (ctx.seen_objects.get(expr.data.e_object)) |obj| {
1045	                    return obj;
1046	                }
1047	
1048	                var obj = JSValue.createEmptyObject(ctx.global, expr.data.e_object.properties.len);
1049	
1050	                args.append(obj);
1051	                try ctx.seen_objects.put(expr.data.e_object, obj);
1052	
1053	                for (expr.data.e_object.properties.slice()) |prop| {
1054	                    const key_expr = prop.key.?;
1055	                    const value_expr = prop.value.?;
1056	
1057	                    const key = try ctx.toJS(args, key_expr);
1058	                    const value = try ctx.toJS(args, value_expr);
1059	
1060	                    const key_str = try key.toBunString(ctx.global);
1061	                    defer key_str.deref();
1062	
1063	                    try obj.putMayBeIndex(ctx.global, &key_str, value);
1064	                }
1065	
1066	                return obj;
1067	            },
1068	
1069	            // unreachable. the yaml AST does not use any other
1070	            // expr types
1071	            else => return .js_undefined,
1072	        }
1073	    }
1074	};
